import ast
import re

def validate_code_safety(code: str) -> dict:
    issues = []

    # Check for dangerous imports
    dangerous_imports = ['os.system', 'subprocess.call', 'exec', 'eval']
    for dangerous in dangerous_imports:
        if dangerous in code:
            issues.append(f"Dangerous pattern: {dangerous}")

    # Syntax validation
    try:
        ast.parse(code)
    except SyntaxError as e:
        issues.append(f"Syntax error: {e}")

    # Credential patterns
    cred_patterns = [r'api[_-]?key', r'password', r'secret']
    for pattern in cred_patterns:
        if re.search(pattern, code, re.IGNORECASE):
            issues.append(f"Potential credential leakage: {pattern}")

    return {"safe": len(issues) == 0, "issues": issues}

# Usage
safety_check = validate_code_safety(generated_code)
if not safety_check['safe']:
    raise ValueError(f"Code rejected: {safety_check['issues']}")

