class VexSandboxExecutor(SandboxExecutor):
    def _run(self, code: str, timeout: int = 30) -> str:
        # Pre-execution Vex check
        deps_check = vex.verify({
            "input": code,
            "policy": "dependency-safety",
            "checks": ["dependency_safety", "execution_sandboxing"]
        })

        if not deps_check.passed:
            return f"VEX BLOCKED: {deps_check.issues}"

        # Execute only if safe
        result = super()._run(code, timeout)

        # Post-execution verification
        exec_check = vex.verify({
            "input": result,
            "policy": "execution-safety",
            "checks": ["execution_sandboxing"]
        })

        return result if exec_check.passed else f"VEX POST-EXEC BLOCK: {exec_check.issues}"

# Replace standard executor
tester_tools = [VexSandboxExecutor()]
tester = Agent(..., tools=tester_tools)

from vex_sdk import VexClient

vex = VexClient(api_key="your-vex-api-key")
crew_state = {"iterations": 0, "delegations": set()}

def vex_crew_guardrail(crew):
    # Track delegation patterns
    current_state = {
        "crew_id": id(crew),
        "iteration": crew_state["iterations"],
        "recent_delegations": list(crew_state["delegations"][-5:]),
        "task_objectives": [t.description for t in crew.tasks]
    }

    loop_check = vex.verify({
        "input": current_state,
        "policy": "crewai-loop-prevention",
        "checks": ["delegation_loops", "task_drift", "iteration_limit"]
    })

    if not loop_check.passed:
        raise RuntimeError(f"Crew loop detected: {loop_check.issues}")

    crew_state["iterations"] += 1
    crew_state["delegations"].add(f"{crew.active_agent.role}->{len(crew.tasks)}")

# Hook into crew execution
crew = Crew(..., guardrail=vex_crew_guardrail)
result = crew.kickoff()
